use std::collections::HashMap;

struct JobQueue<T> {
    jobs: HashMap<String, T>,
}

impl<T> JobQueue<T> {
    fn new() -> Self {
        JobQueue { jobs: HashMap::new() }
    }

    fn enqueue(&mut self, job_id: String, data: T) {
        self.jobs.insert(job_id, data);
    }

    fn dequeue(&mut self) -> Option<String> {
        let id = self.jobs.keys().next().cloned();
        if let Some(id) = id {
            self.jobs.remove(&id);
            Some(id)
        } else {
            None
        }
    }
}

fn main() {
    let mut email_queue: JobQueue<String> = JobQueue::new();

    email_queue.enqueue("job-1024".to_string(), "recipient@example.com".to_string());
    email_queue.enqueue("job-1025".to_string(), "admin@localnet.org".to_string());

    if let Some(id) = email_queue.dequeue() {
        println!("Successfully retrieved job ID: {}", id);
    }

    let mut report_queue: JobQueue<i32> = JobQueue::new();
    report_queue.enqueue("job-900".to_string(), 42);

    if let Some(id) = report_queue.dequeue() {
        println!("Successfully retrieved job ID: {}", id);
    }
}

