use std::collections::HashSet;

fn main() {
    let existing_ids = vec!["user_abc", "user_xyz", "user_def"];
    let new_id_to_check = "user_abc";
    let another_id = "user_ghi";

    let mut id_set: HashSet<String> = HashSet::new();

    for id in existing_ids {
        id_set.insert(id.to_string());
    }

    let is_present_1 = id_set.contains(&new_id_to_check.to_string());
