}

use std::collections::HashMap;

struct ConfigReader<'a> {
    data: &'a str,
}

impl<'a> ConfigReader<'a> {
    fn new(data: &'a str) -> Self {
        ConfigReader { data }
    }

    fn get_setting(&self, key: &str) -> Option<&'a str> {
        let parts: Vec<&str> = self.data.split(':').collect();
        for i in 0..parts.len().saturating_sub(1) {
            if parts[i].trim() == key.trim() {
                return Some(parts[i+1].trim());
            }
        }
        None
    }
}

fn main() {
    let file_content = "version: 2.0n author: Jane Doen path: /etc/app";
    let reader = ConfigReader::new(file_content);

    match reader.get_setting("author") {
        Some(author) => println!("Found author: {}", author),
        None => println!("Author setting not found.")
    }

    let path = reader.get_setting("path");
    if let Some(p) = path {
        println!("Configuration path is: {}", p);
    }
}
